"required":false,"default":"During the term of this Agreement and for twelve (12) months thereafter, neither party shall solicit for hire any employee or contractor of the other party, nor solicit the other party''s clients or customers for competing purposes, without prior written consent."},{"name":"change_request_clause","label":"Change Requests","type":"textarea","required":false,"default":"Any changes to the scope described in this Agreement must be agreed in writing by both parties, including any associated adjustments to fees or timelines, before such changes take effect."},{"name":"insurance_clause","label":"Insurance","type":"textarea","required":false,"default":"Where applicable, each party shall maintain insurance coverage appropriate to its obligations under this Agreement and shall provide proof of such coverage upon the other party''s reasonable request."},{"name":"governing_law","label":"Governing Law / Jurisdiction","type":"text","required":false},{"name":"witness_name","label":"Witness Name (optional)","type":"text","required":false},{"name":"party_a_signature","label":"Party A Signature","type":"signature","required":false},{"name":"party_b_signature","label":"Party B Signature","type":"signature","required":false}]}' WHERE slug = 'contract-agreement-generator';
