SELECT 3, 'Franchise Agreement Generator', 'franchise-agreement-generator', 'Create a professional franchise agreement online in minutes — define territory, fees, and royalty terms, preview instantly, and download as PDF or DOCX.', 'Create a professional franchise agreement online in minutes — define territory, fees, and royalty terms, preview instantly, and download as PDF or DOCX.', 'bi-shop', 'free', '{"fields":[{"name":"agreement_date","label":"Agreement Date","type":"date","required":true},{"name":"franchisor","label":"Franchisor","type":"party","required":true},{"name":"franchisee","label":"Franchisee","type":"party","required":true},{"name":"business_name","label":"Franchise / Business Name","type":"text","required":true},{"name":"territory","label":"Territory / Location","type":"text","required":false},{"name":"franchise_fee","label":"Initial Franchise Fee","type":"text","required":false},{"name":"royalty_terms","label":"Royalty / Ongoing Fee Terms","type":"textarea","required":false},{"name":"start_date","label":"Start Date","type":"date","required":false},{"name":"end_date","label":"End Date","type":"date","required":false},{"name":"background","label":"Background / Recitals","type":"textarea","required":false,"default":"This Agreement is entered into between the parties for the purpose described herein. Each party confirms that it has the full right, power, and authority to enter into this Agreement and to perform its obligations under it."},{"name":"confidentiality_clause","label":"Confidentiality","type":"textarea","required":false,"default":"Each party agrees to keep confidential all non-public information disclosed by the other party in connection with this Agreement, including trade secrets, customer data, financial information, and business processes, and shall not disclose such information to any third party without prior written consent, except as required by law."},{"name":"intellectual_property_clause","label":"Intellectual Property Rights","type":"textarea","required":false,"default":"Each party retains all rights, title, and interest in its pre-existing intellectual property. Ownership of any new intellectual property created specifically under this Agreement shall be as agreed in writing between the parties; absent such agreement, each party retains ownership of its own contributions."},{"name":"warranty_clause","label":"Warranty","type":"textarea","required":false,"default":"Except as expressly stated in this Agreement, each party provides its performance on an as-is basis with a limited warranty that services and deliverables will be performed in a professional and workmanlike manner consistent with industry standards."},{"name":"liability_clause","label":"Limitation of Liability","type":"textarea","required":false,"default":"To the maximum extent permitted by law, neither party''s total liability arising out of or relating to this Agreement shall exceed the total fees paid or payable under this Agreement in the twelve (12) months preceding the event giving rise to the claim, except for liability arising from gross negligence, willful misconduct, or breach of confidentiality obligations."},{"name":"indemnification_clause","label":"Indemnification","type":"textarea","required":false,"default":"Each party agrees to indemnify, defend, and hold harmless the other party from and against any third-party claims, damages, losses, or expenses (including reasonable legal fees) arising out of its breach of this Agreement, negligence, or willful misconduct."},{"name":"force_majeure_clause","label":"Force Majeure","type":"textarea","required":false,"default":"Neither party shall be liable for any failure or delay in performance due to causes beyond its reasonable control, including acts of war, natural disasters, government restrictions, or internet or utility outages."},{"name":"termination_clause","label":"Termination","type":"textarea","required":false,"default":"Either party may terminate this Agreement for convenience by providing thirty (30) days'' written notice to the other party. Either party may terminate immediately upon the other party''s material breach that remains uncured for fifteen (15) days after written notice, or upon the other party''s insolvency or bankruptcy."},{"name":"dispute_resolution_clause","label":"Dispute Resolution","type":"textarea","required":false,"default":"The parties shall first attempt to resolve any dispute arising out of this Agreement through good-faith negotiation. If the dispute is not resolved within thirty (30) days, the parties agree to submit the dispute to binding arbitration or, where the parties mutually agree, mediation, prior to pursuing court litigation, except where injunctive relief is required."},{"name":"assignment_clause","label":"Assignment","type":"textarea","required":false,"default":"Neither party may assign or transfer its rights or obligations under this Agreement without the prior written consent of the other party, except in connection with a merger, acquisition, or sale of substantially all of its assets."},{"name":"entire_agreement_clause","label":"Entire Agreement","type":"textarea","required":false,"default":"This Agreement constitutes the entire agreement between the parties with respect to its subject matter and supersedes all prior or contemporaneous agreements, understandings, and communications, whether written or oral."},{"name":"severability_clause","label":"Severability","type":"textarea","required":false,"default":"If any provision of this Agreement is held to be invalid or unenforceable, the remaining provisions shall continue in full force and effect, and the invalid provision shall be deemed modified to the minimum extent necessary to make it enforceable."},{"name":"electronic_signature_clause","label":"Electronic Signature","type":"textarea","required":false,"default":"The parties agree that this Agreement may be executed electronically and that electronic signatures, including typed, drawn, or uploaded signatures, shall have the same legal effect as handwritten signatures."},{"name":"data_protection_clause","label":"Data Protection & Privacy","type":"textarea","required":false,"default":"Each party shall handle any personal data obtained in connection with this Agreement in accordance with applicable data protection laws (including, where applicable, GDPR, UK GDPR, CCPA, or PIPEDA) and shall implement reasonable safeguards against unauthorized access, use, or disclosure of such data."},{"name":"non_solicitation_clause","label":"Non-Solicitation","type":"textarea","required":false,"default":"During the term of this Agreement and for twelve (12) months thereafter, neither party shall solicit for hire any employee or contractor of the other party, nor solicit the other party''s clients or customers for competing purposes, without prior written consent."},{"name":"non_compete_clause","label":"Non-Compete","type":"textarea","required":false,"default":"Where legally permitted, each party agrees not to engage in any business directly competing with the other party''s business within the same market for a reasonable period following termination of this Agreement, to the extent enforceable under applicable law."},{"name":"governing_law","label":"Governing Law / Jurisdiction","type":"text","required":false},{"name":"additional_terms","label":"Additional Terms & Conditions","type":"textarea","required":false},{"name":"witness_name","label":"Witness Name (optional)","type":"text","required":false},{"name":"franchisor_signature","label":"Franchisor Signature","type":"signature","required":false},{"name":"franchisee_signature","label":"Franchisee Signature","type":"signature","required":false}]}', '[{"q":"Is the Franchise Agreement Generator free to use?","a":"Yes, every Invoxaco plan includes access to this tool. Free plan documents are watermarked and limited to 10 per month; Pro and Premium plans remove the watermark and raise or remove the limit."},{"q":"Does this cover franchise disclosure document requirements?","a":"No. Many jurisdictions require a separate franchise disclosure document before signing; this generator produces the agreement itself, not the regulatory disclosure filing. Consult an attorney for franchise-specific compliance."},{"q":"Can I define an exclusive territory?","a":"Yes, describe territory exclusivity in the Territory / Location field or the Additional Terms field."}]', 1, 1, 'Franchise Agreement Generator - Free Online Franchise Agreement Generator | Invoxaco', 'Create a professional franchise agreement online in minutes — define territory, fees, and royalty terms, preview instantly, and download as PDF or DOCX.', 21
WHERE NOT EXISTS (SELECT 1 FROM document_templates WHERE slug = 'franchise-agreement-generator');
