SELECT 3, 'Commission Agreement Generator', 'commission-agreement-generator', 'Create a professional commission agreement online in minutes — define commission structure, products, and payment terms, preview instantly, and download as PDF or DOCX.', 'Create a professional commission agreement online in minutes — define commission structure, products, and payment terms, preview instantly, and download as PDF or DOCX.', 'bi-percent', 'free', '{"fields":[{"name":"agreement_date","label":"Agreement Date","type":"date","required":true},{"name":"principal","label":"Principal / Company","type":"party","required":true},{"name":"agent","label":"Sales Agent / Representative","type":"party","required":true},{"name":"products_services","label":"Products / Services Covered","type":"textarea","required":true},{"name":"commission_structure","label":"Commission Structure & Rates","type":"textarea","required":true},{"name":"payment_terms","label":"Payment Terms","type":"textarea","required":false},{"name":"start_date","label":"Start Date","type":"date","required":false},{"name":"end_date","label":"End Date","type":"date","required":false},{"name":"background","label":"Background / Recitals","type":"textarea","required":false,"default":"This Agreement is entered into between the parties for the purpose described herein. Each party confirms that it has the full right, power, and authority to enter into this Agreement and to perform its obligations under it."},{"name":"confidentiality_clause","label":"Confidentiality","type":"textarea","required":false,"default":"Each party agrees to keep confidential all non-public information disclosed by the other party in connection with this Agreement, including trade secrets, customer data, financial information, and business processes, and shall not disclose such information to any third party without prior written consent, except as required by law."},{"name":"intellectual_property_clause","label":"Intellectual Property Rights","type":"textarea","required":false,"default":"Each party retains all rights, title, and interest in its pre-existing intellectual property. Ownership of any new intellectual property created specifically under this Agreement shall be as agreed in writing between the parties; absent such agreement, each party retains ownership of its own contributions."},{"name":"warranty_clause","label":"Warranty","type":"textarea","required":false,"default":"Except as expressly stated in this Agreement, each party provides its performance on an as-is basis with a limited warranty that services and deliverables will be performed in a professional and workmanlike manner consistent with industry standards."},{"name":"liability_clause","label":"Limitation of Liability","type":"textarea","required":false,"default":"To the maximum extent permitted by law, neither party''s total liability arising out of or relating to this Agreement shall exceed the total fees paid or payable under this Agreement in the twelve (12) months preceding the event giving rise to the claim, except for liability arising from gross negligence, willful misconduct, or breach of confidentiality obligations."},{"name":"indemnification_clause","label":"Indemnification","type":"textarea","required":false,"default":"Each party agrees to indemnify, defend, and hold harmless the other party from and against any third-party claims, damages, losses, or expenses (including reasonable legal fees) arising out of its breach of this Agreement, negligence, or willful misconduct."},{"name":"force_majeure_clause","label":"Force Majeure","type":"textarea","required":false,"default":"Neither party shall be liable for any failure or delay in performance due to causes beyond its reasonable control, including acts of war, natural disasters, government restrictions, or internet or utility outages."},{"name":"termination_clause","label":"Termination","type":"textarea","required":false,"default":"Either party may terminate this Agreement for convenience by providing thirty (30) days'' written notice to the other party. Either party may terminate immediately upon the other party''s material breach that remains uncured for fifteen (15) days after written notice, or upon the other party''s insolvency or bankruptcy."},{"name":"dispute_resolution_clause","label":"Dispute Resolution","type":"textarea","required":false,"default":"The parties shall first attempt to resolve any dispute arising out of this Agreement through good-faith negotiation. If the dispute is not resolved within thirty (30) days, the parties agree to submit the dispute to binding arbitration or, where the parties mutually agree, mediation, prior to pursuing court litigation, except where injunctive relief is required."},{"name":"assignment_clause","label":"Assignment","type":"textarea","required":false,"default":"Neither party may assign or transfer its rights or obligations under this Agreement without the prior written consent of the other party, except in connection with a merger, acquisition, or sale of substantially all of its assets."},{"name":"entire_agreement_clause","label":"Entire Agreement","type":"textarea","required":false,"default":"This Agreement constitutes the entire agreement between the parties with respect to its subject matter and supersedes all prior or contemporaneous agreements, understandings, and communications, whether written or oral."},{"name":"severability_clause","label":"Severability","type":"textarea","required":false,"default":"If any provision of this Agreement is held to be invalid or unenforceable, the remaining provisions shall continue in full force and effect, and the invalid provision shall be deemed modified to the minimum extent necessary to make it enforceable."},{"name":"electronic_signature_clause","label":"Electronic Signature","type":"textarea","required":false,"default":"The parties agree that this Agreement may be executed electronically and that electronic signatures, including typed, drawn, or uploaded signatures, shall have the same legal effect as handwritten signatures."},{"name":"data_protection_clause","label":"Data Protection & Privacy","type":"textarea","required":false,"default":"Each party shall handle any personal data obtained in connection with this Agreement in accordance with applicable data protection laws (including, where applicable, GDPR, UK GDPR, CCPA, or PIPEDA) and shall implement reasonable safeguards against unauthorized access, use, or disclosure of such data."},{"name":"non_solicitation_clause","label":"Non-Solicitation","type":"textarea","required":false,"default":"During the term of this Agreement and for twelve (12) months thereafter, neither party shall solicit for hire any employee or contractor of the other party, nor solicit the other party''s clients or customers for competing purposes, without prior written consent."},{"name":"non_compete_clause","label":"Non-Compete","type":"textarea","required":false,"default":"Where legally permitted, each party agrees not to engage in any business directly competing with the other party''s business within the same market for a reasonable period following termination of this Agreement, to the extent enforceable under applicable law."},{"name":"governing_law","label":"Governing Law / Jurisdiction","type":"text","required":false},{"name":"additional_terms","label":"Additional Terms & Conditions","type":"textarea","required":false},{"name":"witness_name","label":"Witness Name (optional)","type":"text","required":false},{"name":"principal_signature","label":"Principal Signature","type":"signature","required":false},{"name":"agent_signature","label":"Agent Signature","type":"signature","required":false}]}', '[{"q":"Is the Commission Agreement Generator free to use?","a":"Yes, every Invoxaco plan includes access to this tool. Free plan documents are watermarked and limited to 10 per month; Pro and Premium plans remove the watermark and raise or remove the limit."},{"q":"Can I define tiered commission rates?","a":"Yes, describe tiered or sliding-scale commission rates in the Commission Structure & Rates field."},{"q":"Does this cover commission on renewals or recurring revenue?","a":"Yes, specify renewal or recurring commission terms in the Commission Structure & Rates or Additional Terms fields."}]', 1, 1, 'Commission Agreement Generator - Free Online Commission Agreement Generator | Invoxaco', 'Create a professional commission agreement online in minutes — define commission structure, products, and payment terms, preview instantly, and download as PDF or DOCX.', 24
WHERE NOT EXISTS (SELECT 1 FROM document_templates WHERE slug = 'commission-agreement-generator');
INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order)
SELECT 3, 'Terms of Service Generator', 'terms-of-service-generator', 'Create a professional Terms of Service page online in minutes — covers user accounts, acceptable use, IP, liability, and termination, preview instantly, and download as PDF or DOCX.', 'Create a professional Terms of Service page online in minutes — covers user accounts, acceptable use, IP, liability, and termination, preview instantly, and download as PDF or DOCX.', 'bi-file-text', 'free', '{"fields":[{"name":"effective_date","label":"Effective Date","type":"date","required":true},{"name":"company","label":"Company / Website Operator","type":"party","required":true},{"name":"website_name","label":"Website / Service Name","type":"text","required":true},{"name":"acceptance_of_terms","label":"Acceptance of Terms","type":"textarea","required":false,"default":"By accessing or using this website or service, you agree to be bound by these Terms of Service. If you do not agree to these terms, please do not use the service."},{"name":"user_accounts","label":"User Accounts","type":"textarea","required":false,"default":"Users may be required to create an account to access certain features. You are responsible for maintaining the confidentiality of your account credentials and for all activity that occurs under your account."},{"name":"acceptable_use","label":"Acceptable Use","type":"textarea","required":false,"default":"You agree not to use the service for any unlawful purpose, to infringe the rights of others, to transmit harmful code, or to interfere with the operation of the service."},{"name":"intellectual_property_clause","label":"Intellectual Property Rights","type":"textarea","required":false,"default":"Each party retains all rights, title, and interest in its pre-existing intellectual property. Ownership of any new intellectual property created specifically under this Agreement shall be as agreed in writing between the parties; absent such agreement, each party retains ownership of its own contributions."},{"name":"disclaimer_of_warranties","label":"Disclaimer of Warranties","type":"textarea","required":false,"default":"The service is provided as is and as available without warranties of any kind, either express or implied, including but not limited to warranties of merchantability, fitness for a particular purpose, or non-infringement."},{"name":"liability_clause","label":"Limitation of Liability","type":"textarea","required":false,"default":"To the maximum extent permitted by law, neither party''s total liability arising out of or relating to this Agreement shall exceed the total fees paid or payable under this Agreement in the twelve (12) months preceding the event giving rise to the claim, except for liability arising from gross negligence, willful misconduct, or breach of confidentiality obligations."},{"name":"termination_clause","label":"Termination","type":"textarea","required":false,"default":"Either party may terminate this Agreement for convenience by providing thirty (30) days'' written notice to the other party. Either party may terminate immediately upon the other party''s material breach that remains uncured for fifteen (15) days after written notice, or upon the other party''s insolvency or bankruptcy."},{"name":"governing_law","label":"Governing Law / Jurisdiction","type":"text","required":false},{"name":"changes_to_terms","label":"Changes to These Terms","type":"textarea","required":false,"default":"We may update these Terms of Service from time to time. Continued use of the service after changes take effect constitutes acceptance of the revised terms."},{"name":"contact_information","label":"Contact Information","type":"textarea","required":true,"default":"If you have any questions about these Terms of Service, please contact us using the details provided on our website."}]}', '[{"q":"Is the Terms of Service Generator free to use?","a":"Yes, every Invoxaco plan includes access to this tool. Free plan documents are watermarked and limited to 10 per month; Pro and Premium plans remove the watermark and raise or remove the limit."},{"q":"Do I need to sign a Terms of Service page?","a":"No, Terms of Service are a unilateral policy published by the website or service operator, not a document signed by both parties — there is no signature section."},{"q":"Does this replace legal review?","a":"No. This generator produces a generic, editable starting point. Businesses with specific regulatory obligations should have the final terms reviewed by a qualified attorney."}]', 1, 1, 'Terms of Service Generator - Free Online Terms of Service Generator | Invoxaco', 'Create a professional Terms of Service page online in minutes — covers user accounts, acceptable use, IP, liability, and termination, preview instantly, and download as PDF or DOCX.', 25
WHERE NOT EXISTS (SELECT 1 FROM document_templates WHERE slug = 'terms-of-service-generator');
