SELECT 3, 'Privacy Policy Generator', 'privacy-policy-generator', 'Create a professional Privacy Policy online in minutes — covers data collection, usage, sharing, security, and user rights, preview instantly, and download as PDF or DOCX.', 'Create a professional Privacy Policy online in minutes — covers data collection, usage, sharing, security, and user rights, preview instantly, and download as PDF or DOCX.', 'bi-incognito', 'free', '{"fields":[{"name":"effective_date","label":"Effective Date","type":"date","required":true},{"name":"company","label":"Company / Website Operator","type":"party","required":true},{"name":"website_name","label":"Website / Service Name","type":"text","required":true},{"name":"information_collected","label":"Information We Collect","type":"textarea","required":false,"default":"We may collect personal information such as your name, email address, contact details, and usage data when you interact with our website or service."},{"name":"how_information_is_used","label":"How We Use Your Information","type":"textarea","required":false,"default":"We use the information we collect to provide and improve our services, communicate with you, process transactions, and comply with legal obligations."},{"name":"cookies_tracking","label":"Cookies & Tracking","type":"textarea","required":false,"default":"We may use cookies and similar tracking technologies to enhance your experience. See our Cookie Policy for further details."},{"name":"data_sharing","label":"Data Sharing & Third Parties","type":"textarea","required":false,"default":"We do not sell your personal information. We may share information with trusted service providers who assist in operating our business, subject to confidentiality obligations, or as required by law."},{"name":"data_security","label":"Data Security","type":"textarea","required":false,"default":"We implement reasonable technical and organizational measures designed to protect your personal information against unauthorized access, alteration, disclosure, or destruction."},{"name":"user_rights","label":"Your Rights","type":"textarea","required":false,"default":"Depending on your jurisdiction, you may have rights to access, correct, delete, or restrict the use of your personal data under applicable laws such as the GDPR, UK GDPR, CCPA, or PIPEDA. Contact us to exercise these rights."},{"name":"childrens_privacy","label":"Children''s Privacy","type":"textarea","required":false,"default":"Our service is not directed to children under the age of 13, and we do not knowingly collect personal information from children."},{"name":"changes_to_policy","label":"Changes to This Policy","type":"textarea","required":false,"default":"We may update this Privacy Policy from time to time. We will post any changes on this page with an updated effective date."},{"name":"contact_information","label":"Contact Information","type":"textarea","required":true,"default":"If you have any questions about this Privacy Policy, please contact us using the details provided on our website."}]}', '[{"q":"Is the Privacy Policy Generator free to use?","a":"Yes, every Invoxaco plan includes access to this tool. Free plan documents are watermarked and limited to 10 per month; Pro and Premium plans remove the watermark and raise or remove the limit."},{"q":"Does this make my business GDPR or CCPA compliant?","a":"This generator produces a generic, editable starting point that references common frameworks like GDPR and CCPA, but full compliance depends on your specific data practices. Consult a qualified attorney for compliance advice."},{"q":"Can I edit the default clauses?","a":"Yes, every section is a fully editable text field so you can tailor the policy to your actual data practices."}]', 1, 1, 'Privacy Policy Generator - Free Online Privacy Policy Generator | Invoxaco', 'Create a professional Privacy Policy online in minutes — covers data collection, usage, sharing, security, and user rights, preview instantly, and download as PDF or DOCX.', 26
WHERE NOT EXISTS (SELECT 1 FROM document_templates WHERE slug = 'privacy-policy-generator');
