SELECT 3, 'Cookie Policy Generator', 'cookie-policy-generator', 'Create a professional Cookie Policy online in minutes — explain what cookies your site uses and how visitors can manage them, preview instantly, and download as PDF or DOCX.', 'Create a professional Cookie Policy online in minutes — explain what cookies your site uses and how visitors can manage them, preview instantly, and download as PDF or DOCX.', 'bi-cookie', 'free', '{"fields":[{"name":"effective_date","label":"Effective Date","type":"date","required":true},{"name":"company","label":"Company / Website Operator","type":"party","required":true},{"name":"website_name","label":"Website / Service Name","type":"text","required":true},{"name":"what_are_cookies","label":"What Are Cookies","type":"textarea","required":false,"default":"Cookies are small text files placed on your device when you visit a website. They help the website remember information about your visit, such as preferences and login status."},{"name":"types_of_cookies_used","label":"Types of Cookies We Use","type":"textarea","required":false,"default":"We use essential cookies required for the website to function, performance cookies to understand how visitors use our site, and functionality cookies to remember your preferences."},{"name":"third_party_cookies","label":"Third-Party Cookies","type":"textarea","required":false,"default":"Some cookies may be placed by third-party services we use, such as analytics or advertising partners. These third parties have their own privacy and cookie policies."},{"name":"managing_cookies","label":"Managing Cookies","type":"textarea","required":false,"default":"You can control or delete cookies through your browser settings. Disabling certain cookies may affect the functionality of our website."},{"name":"changes_to_policy","label":"Changes to This Policy","type":"textarea","required":false,"default":"We may update this Cookie Policy from time to time. We will post any changes on this page with an updated effective date."},{"name":"contact_information","label":"Contact Information","type":"textarea","required":true,"default":"If you have any questions about this Cookie Policy, please contact us using the details provided on our website."}]}', '[{"q":"Is the Cookie Policy Generator free to use?","a":"Yes, every Invoxaco plan includes access to this tool. Free plan documents are watermarked and limited to 10 per month; Pro and Premium plans remove the watermark and raise or remove the limit."},{"q":"Do I need a separate Cookie Policy from my Privacy Policy?","a":"Many businesses combine both into one document, while others (especially in the EU/UK under ePrivacy rules) publish a separate Cookie Policy. This generator lets you produce either as a standalone page."},{"q":"Does this include a cookie consent banner?","a":"No, this generator produces the policy text only. You will still need to implement a cookie consent banner on your website if required in your jurisdiction."}]', 1, 1, 'Cookie Policy Generator - Free Online Cookie Policy Generator | Invoxaco', 'Create a professional Cookie Policy online in minutes — explain what cookies your site uses and how visitors can manage them, preview instantly, and download as PDF or DOCX.', 27
WHERE NOT EXISTS (SELECT 1 FROM document_templates WHERE slug = 'cookie-policy-generator');
