SELECT 3, 'Refund Policy Generator', 'refund-policy-generator', 'Create a professional Refund Policy online in minutes — define eligibility, process, and timeframes for refunds, preview instantly, and download as PDF or DOCX.', 'Create a professional Refund Policy online in minutes — define eligibility, process, and timeframes for refunds, preview instantly, and download as PDF or DOCX.', 'bi-arrow-counterclockwise', 'free', '{"fields":[{"name":"effective_date","label":"Effective Date","type":"date","required":true},{"name":"company","label":"Company / Business","type":"party","required":true},{"name":"business_name","label":"Business Name","type":"text","required":true},{"name":"refund_eligibility","label":"Refund Eligibility","type":"textarea","required":true,"default":"Customers may request a refund within the timeframe stated below if the product or service did not meet the description provided, or as otherwise required by applicable consumer protection law."},{"name":"refund_process","label":"How to Request a Refund","type":"textarea","required":false,"default":"To request a refund, contact us using the details below with your order or invoice number and the reason for the request. We will review and respond within a reasonable time."},{"name":"refund_timeframe","label":"Refund Timeframe","type":"text","required":false,"default":"5-10 business days"},{"name":"non_refundable_items","label":"Non-Refundable Items / Exceptions","type":"textarea","required":false,"default":"Certain products or services may be non-refundable, including custom or personalized work, downloadable digital products once accessed, and services already substantially performed."},{"name":"contact_information","label":"Contact Information","type":"textarea","required":true,"default":"If you have any questions about this Refund Policy, please contact us using the details provided on our website."}]}', '[{"q":"Is the Refund Policy Generator free to use?","a":"Yes, every Invoxaco plan includes access to this tool. Free plan documents are watermarked and limited to 10 per month; Pro and Premium plans remove the watermark and raise or remove the limit."},{"q":"Can I list specific non-refundable products?","a":"Yes, the Non-Refundable Items / Exceptions field is fully editable so you can list any specific exclusions relevant to your business."},{"q":"Does this comply with consumer protection law in my country?","a":"This generator produces a generic, editable starting point. Refund and consumer protection requirements vary by country, so review your final policy against local law or consult an attorney."}]', 1, 1, 'Refund Policy Generator - Free Online Refund Policy Generator | Invoxaco', 'Create a professional Refund Policy online in minutes — define eligibility, process, and timeframes for refunds, preview instantly, and download as PDF or DOCX.', 28
WHERE NOT EXISTS (SELECT 1 FROM document_templates WHERE slug = 'refund-policy-generator');

